            {props.temperature}°{unit}
          </Heading>
          <Button variant="ghost" size="sm" onClick={toggleUnit}>Switch Unit</Button>
        </Stack>
        <Row justify="between">
          <Box><Text variant="label">Humidity</Text><Text>{props.humidity}%</Text></Box>
          <Box><Text variant="label">Wind</Text><Text>{props.windSpeed} km/h</Text></Box>
        </Row>
        <Divider margin={8} />
        <Row justify="between" gap={8}>
          {props.forecast.map((day, i) => (
            <Stack key={i} align="center" gap={4}>
              <Text variant="caption">{day.day}</Text>
              <Icon name={day.icon as any} size={20} aria-label={`${day.icon} condition`} />
              <Text variant="bodySmall">{day.high}°/{day.low}°</Text>
            </Stack>
          ))}
