import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: { id: string; title: string; priority: string; assignee: string; column: string; dueDate: string }[]; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');

  const moveTask = (taskId: string, newColumn: string) => {
    const updatedTasks = tasks.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t));
    setTasks(updatedTasks);
    handleTaskUpdate({ type: 'MOVE', taskId, newColumn });
  };

  const addTask = (columnId: string) => {
    if (!newTaskTitle) return;
    const newTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: '??',
      column: columnId,
      dueDate: new Date().toLocaleDateString(),
    };
    setTasks([...tasks, newTask]);
    setNewTaskTitle('');
    setIsAdding(null);
    handleTaskUpdate({ type: 'CREATE', task: newTask });
  };

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  return { tasks, moveTask, addTask, isAdding, setIsAdding, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, totalTasks, completedTasks };
}

export default function Component(props: Props) {
  const { tasks, moveTask, addTask, isAdding, setIsAdding, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority, totalTasks, completedTasks } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16}>
        <Row justify="between" align="center">
          <Heading level={1}>Task Board</Heading>
          <Row gap={16}>
            <Badge variant="primary">{totalTasks} Total</Badge>
            <Badge variant="success">{completedTasks} Completed</Badge>
          </Row>
        </Row>
        <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
          {props.columns.map((col) => (
            <Stack key={col.id || 'none'} gap={16} style={{ background: 'var(--ggui-color-surfaceVariant)', padding: 'var(--ggui-spacing-4)', borderRadius: 'var(--ggui-shape-radius-lg)' }}>
              <Row justify="between" align="center">
                <Heading level={3}>{col.name || 'Untitled'}</Heading>
                <Badge variant="secondary">{tasks.filter(t => t.column === col.id).length}</Badge>
              </Row>
              <Stack gap={12}>
                {tasks.filter(t => t.column === col.id).map(task => (
                  <Card key={task.id} padding={16} shadow="sm" radius="md">
                    <Stack gap={8}>
                      <Text variant="body" weight="medium">{task.title}</Text>
                      <Row justify="between" align="center" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
                        <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'info'} size="sm" pill={false}>
                          {task.priority.toUpperCase()}
                        </Badge>
                        <Avatar name={task.assignee} size={32} />
                      </Row>
                      <Box style={{ marginTop: 'var(--ggui-spacing-2)' }}>
                        <Select value={col.id || ''} onChange={(newCol) => moveTask(task.id, newCol)} options={props.columns.map(c => ({ value: c.id || '', label: `Move to ${c.name}` }))} size="sm" />
                      </Box>
                    </Stack>
                  </Card>
                ))}
              </Stack>
              {isAdding === col.id ? (
                <Stack gap={12} style={{ marginTop: 'var(--ggui-spacing-4)' }}>
                  <Input label="Task Title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Task title" />
                  <Select label="Priority" value={newTaskPriority} onChange={setNewTaskPriority} options={[{value:'low', label:'Low'}, {value:'medium', label:'Medium'}, {value:'high', label:'High'}]} size="md" />
                  <Row gap={8}>
                    <Button size="md" onClick={() => addTask(col.id || '')}>Save Task</Button>
                    <Button size="sm" variant="ghost" onClick={() => setIsAdding(null)}>Cancel</Button>
                  </Row>
                </Stack>
              ) : (
                <Button variant="ghost" fullWidth onClick={() => setIsAdding(col.id || null)}>+ Add Task</Button>
              )}
            </Stack>
          ))}
        </CardGrid>
      </Stack>
    </Container>
  );
}

