import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: { atomicNumber: number; symbol: string; name: string; atomicWeight: number; category: string; row: number; col: number }[]; // Full periodic table element data
}

function useComponent(props: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const categories = useMemo(() => Array.from(new Set(props.elements.map(e => e.category))), [props.elements]);

  const filtered = useMemo(() => {
    const q = search.toLowerCase();
    return props.elements.filter(e => e.name.toLowerCase().includes(q) || e.symbol.toLowerCase().includes(q));
  }, [props.elements, search]);

  const getCategoryColor = useCallback((cat: string) => {
    const colors: Record<string, string> = {
      'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
      'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
      'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
      'noble gas': 'var(--ggui-color-success-500, #22c55e)',
      'halogen': 'var(--ggui-color-info-500, #06b6d4)',
    };
    return colors[cat] || 'var(--ggui-color-neutral-400, #9ca3af)';
  }, []);

  return { search, setSearch, selected, setSelected, filtered, categories, getCategoryColor };
}

export default function Component(props: Props) {
  const { search, setSearch, selected, setSelected, filtered, categories, getCategoryColor } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table</Heading>
        <Row align="center" gap={16}>
          <Box style={{ flex: 1 }}>
            <SearchField value={search} onChange={setSearch} placeholder="Search by name or symbol..." />
          </Box>
        </Row>
        <Row wrap gap={8}>
          {categories.map(c => (
            <Badge key={c} style={{ backgroundColor: getCategoryColor(c), color: 'var(--ggui-color-surface, #ffffff)' }}>{c}</Badge>
          ))}
        </Row>

        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1, 4px)' }}>
          {props.elements.map(e => {
            const isVisible = filtered.includes(e);
            return (
              <Card 
                key={e.symbol}
                as={Clickable}
                aria-label={`Element ${e.name}, atomic number ${e.atomicNumber}, symbol ${e.symbol}`}
                onClick={() => setSelected(e)}
                style={{ 
                  gridColumn: e.col, 
                  gridRow: e.row, 
                  opacity: isVisible ? 1 : 0.1,
                  backgroundColor: getCategoryColor(e.category),
                  color: 'var(--ggui-color-surface, #ffffff)',
                  aspectRatio: '1/1',
                  transition: 'all 200ms ease'
                }}
              >
                <Stack justify="between" style={{ height: '100%' }}>
                  <Text size="xs" color="var(--ggui-color-surface, #ffffff)">{e.atomicNumber}</Text>
                  <Heading level={4} align="center" color="var(--ggui-color-surface, #ffffff)">{e.symbol}</Heading>
                  <Box />
                </Stack>
              </Card>
            );
          })}
        </Box>

        {selected && (
          <Card shadow="md" padding={24}>
            <Stack gap={16}>
              <Row justify="between" align="center">
                <Heading level={3}>{selected.name}</Heading>
                <Badge>{selected.category}</Badge>
              </Row>
              <Row gap={24}>
                <Stack>
                  <Text variant="label">Symbol</Text>
                  <Text>{selected.symbol}</Text>
                </Stack>
                <Stack>
                  <Text variant="label">Atomic Number</Text>
                  <Text>{selected.atomicNumber}</Text>
                </Stack>
                <Stack>
                  <Text variant="label">Atomic Weight</Text>
                  <Text>{selected.atomicWeight}</Text>
                </Stack>
              </Row>
              <Button onClick={() => setSelected(null)}>Close</Button>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

