import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id: string; name: string; price: number; currency: string; rating: number; reviewCount: number; stock: number; description: string; specifications: { label: string; value: string }[]; reviews: { author: string; rating: number; text: string; date: string }[] };
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);

  const isOutOfStock = useMemo(() => props.product.stock === 0, [props.product.stock]);

  const increment = useCallback(() => {
    setQuantity((q) => Math.min(q + 1, props.product.stock));
  }, [props.product.stock]);

  const decrement = useCallback(() => {
    setQuantity((q) => Math.max(q - 1, 1));
  }, []);

  const addToCart = useCallback(() => {
    handleAddToCart({ productId: props.product.id, quantity });
  }, [handleAddToCart, props.product.id, quantity]);

  return { quantity, isOutOfStock, increment, decrement, addToCart };
}

export default function Component(props: Props) {
  const { quantity, isOutOfStock, increment, decrement, addToCart } = useComponent(props);

  const RatingStars = ({ rating }: { rating: number }) => (
    <Row gap={2}>
      {[...Array(5)].map((_, i) => (
        <Icon key={i} name={i < rating ? 'star' : 'star-outline'} size={16} color={i < rating ? '#f59e0b' : '#d4d4d8'} />
      ))}
    </Row>
  );

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack direction="horizontal" gap={32} wrap>
        <Box padding={24} background="var(--ggui-color-surfaceVariant)" borderRadius="lg" style={{ flex: 1, minWidth: 300 }}>
          <Heading level={2}>{props.product.name}</Heading>
        </Box>
        <Stack gap={16} style={{ flex: 1, minWidth: 300 }}>
          <Heading level={1}>{props.product.name}</Heading>
          <Row gap={8} align="center">
            <RatingStars rating={Math.round(props.product.rating)} />
            <Text variant="bodySmall">({props.product.reviewCount} reviews)</Text>
          </Row>
          <Text variant="bodyLarge">{props.product.currency}{props.product.price.toFixed(2)}</Text>
          <Badge variant={isOutOfStock ? 'error' : props.product.stock < 5 ? 'warning' : 'success'}>
            {isOutOfStock ? 'Out of Stock' : props.product.stock < 5 ? 'Low Stock' : 'In Stock'}
          </Badge>
          <Row gap={8} align="center">
            <Button variant="outline" size="sm" onClick={decrement} disabled={quantity <= 1}>-</Button>
            <Text>{quantity}</Text>
            <Button variant="outline" size="sm" onClick={increment} disabled={quantity >= props.product.stock}>+</Button>
            <Button variant="primary" onClick={addToCart} disabled={isOutOfStock}>Add to Cart</Button>
          </Row>
        </Stack>
      </Stack>
      <Spacer size={32} />
      <Tabs items={[
        { key: 'desc', label: 'Description', content: <Text>{props.product.description}</Text> },
        { key: 'specs', label: 'Specifications', content: (
          <Table columns={[{ key: 'label', header: 'Feature' }, { key: 'value', header: 'Detail' }]} data={props.product.specifications} />
        )},
        { key: 'reviews', label: 'Reviews', content: (
          <Stack gap={16}>
            {props.product.reviews.map((r, i) => (
              <Card key={i} padding={16} border={true}>
                <Stack gap={4}>
                  <Row justify="between"><Text variant="label">{r.author}</Text><Text variant="caption">{r.date}</Text></Row>
                  <RatingStars rating={r.rating} />
                  <Text variant="bodySmall">{r.text}</Text>
                </Stack>
              </Card>
            ))}
          </Stack>
        )},
      ]} />
    </Container>
  );
}

