import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState(props.initialProfile || { 
    name: '', email: '', avatar: props.avatarOptions[0], role: '', emailNotifications: true, theme: 'light' 
  });
  const [errors, setErrors] = useState<Record<string, string>>({});

  const isEmailValid = (email: string) => /\S+@\S+\.\S+/.test(email);

  const canNext = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && isEmailValid(formData.email);
    if (step === 2) return formData.role !== '';
    return true;
  }, [step, formData]);

  useEffect(() => {
    const newErrors: Record<string, string> = {};
    if (step === 1) {
      if (formData.name.trim() === '') newErrors.name = 'Name is required';
      if (!isEmailValid(formData.email)) newErrors.email = 'Valid email is required';
    }
    setErrors(newErrors);
  }, [step, formData.name, formData.email]);

  const handleNext = () => step < 3 && setStep(s => s + 1);
  const handleBack = () => step > 1 && setStep(s => s - 1);
  const handleSubmit = () => handleComplete(formData);

  return { step, formData, setFormData, errors, canNext, handleNext, handleBack, handleSubmit };
}

export default function Component(props: Props) {
  const { step, formData, setFormData, canNext, handleNext, handleBack, handleSubmit } = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={16}>
        <Stack gap={4}>
          <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Step {step} of 3</Text>
          <Progress value={(step / 3) * 100} size="sm" />
        </Stack>

        {step === 1 && (
          <Card padding={24}>
            <Heading level={2}>Profile Setup</Heading>
            <Stack gap={16}>
              <FormField label="Name" required error={errors.name}><Input value={formData.name} onChange={(v) => setFormData({...formData, name: v})}/></FormField>
              <FormField label="Email" required error={errors.email}><Input value={formData.email} onChange={(v) => setFormData({...formData, email: v})}/></FormField>
              <Stack gap={4}>
                <Text variant="label">Avatar</Text>
                <Stack direction="horizontal" gap={8} justify="start">
                {props.avatarOptions.map(emoji => (
                  <Button key={emoji} variant={formData.avatar === emoji ? 'primary' : 'outline'} aria-label={`Select avatar ${emoji}`} onClick={() => setFormData({...formData, avatar: emoji})}>{emoji}</Button>
                ))}
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {step === 2 && (
          <Card padding={24}>
            <Heading level={2}>Preferences</Heading>
            <Stack gap={16}>
              <FormField label="Role" required><Select value={formData.role} onChange={(v) => setFormData({...formData, role: v})} options={props.roleOptions.map(r => ({value: r, label: r}))} placeholder="Select a role" /></FormField>
              <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData({...formData, emailNotifications: v})}/>
              <Toggle label="Dark Theme" checked={formData.theme === 'dark'} onChange={(v) => setFormData({...formData, theme: v ? 'dark' : 'light'})}/>
            </Stack>
          </Card>
        )}

        {step === 3 && (
          <Card padding={24}>
            <Heading level={2}>Review</Heading>
            <Divider margin={16}/>
            <Stack gap={12}>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Name: <Text as="span" color="var(--ggui-color-onSurface)">{formData.name}</Text></Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Email: <Text as="span" color="var(--ggui-color-onSurface)">{formData.email}</Text></Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Role: <Text as="span" color="var(--ggui-color-onSurface)">{formData.role}</Text></Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Notifications: <Text as="span" color="var(--ggui-color-onSurface)">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text></Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Theme: <Text as="span" color="var(--ggui-color-onSurface)">{formData.theme === 'dark' ? 'Dark' : 'Light'}</Text></Text>
            </Stack>
          </Card>
        )}

        <Row justify="between">
          <Button variant="outline" disabled={step === 1} onClick={handleBack}>Back</Button>
          {step < 3 ? (
            <Button disabled={!canNext} onClick={handleNext}>Next</Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
